) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '存储及群众实例信息，quartz会实时读取该表判断集群中每个实例的当前状态' ROW_FORMAT = Dynamic;

