  `is_deleted` int(2) NULL DEFAULT NULL COMMENT '是否删除YesNoEnum',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '组件示例表' ROW_FORMAT = Dynamic;

