INSERT INTO `castle_message_email_record` VALUES (1536610562750562306, NULL, '2022-06-14 15:24:42', '我是测试邮件啊', '<p>我是测试邮件啊</p>\n\n<p>你收到邮件了吗</p>\n', -1, NULL, '2022-06-14 15:24:42', -1, '2022-06-14 16:24:17', NULL, 1, '893334248@qq.com;clm0319@126.com', 'clm0319@126.com');
INSERT INTO `castle_message_email_record` VALUES (1536612098268479489, NULL, '2022-06-14 15:30:48', 'xxx招投标方案', '<h1 style=\"text-align: center;\">标题大标题</h1>\n\n<p>我方已经研究过了，这个方案可以通过，需要携带相关的文件来现场进行审核！</p>\n', -1, NULL, '2022-06-14 15:30:48', -1, '2022-06-14 16:24:17', NULL, 1, '893334248@qq.com', '');
INSERT INTO `castle_message_email_record` VALUES (1536618646298443777, NULL, '2022-06-14 15:56:49', '发送一封测试的邮件', '<h1 style=\"text-align: center;\">我是标题</h1>\n\n<p data-source=\"cke\" style=\"text-indent: 2em;\">新华社北京6月13日电 中央军委主席习近平日前签署命令，发布《军队非战争军事行动纲要（试行）》，自2022年6月15日起施行。</p>\n\n<p data-source=\"cke\" style=\"text-indent: 2em;\">《纲要》坚持以习近平新时代中国特色社会主义思想为指导，深入贯彻习近平强军思想，坚持总体国家安全观，着眼有效防范化解风险挑战、应对处置突发事件，保护人民群众生命财产安全，维护国家主权、安全、发展利益，维护世界和平和地区稳定，创新军事力量运用方式，规范军队非战争军事行动组织实施，对有效履行新时代军队使命任务具有重要意义。</p>\n\n<p data-source=\"cke\" style=\"text-indent: 2em;\">《纲要》共6章59条，认真总结以往遂行任务实践经验，广泛汲取军地相关理论成果，主要对基本原则、组织指挥、行动类型、行动保障、政治工作等进行了系统规范，为部队遂行非战争军事行动提供法规依据。</p>\n\n<p data-source=\"cke\">内容分了行也是可以的，添加一个✌ 表情也是😄没有问题的呢，非常好的功能，点个赞👍。</p>\n', -1, NULL, '2022-06-14 15:56:49', -1, '2022-06-14 16:24:17', NULL, 1, '893334248@qq.com', '');
INSERT INTO `castle_message_email_record` VALUES (1536619672753684482, NULL, '2022-06-14 16:00:54', '我是测试啊', '<p>我是测试邮件啊</p>\n', -1, NULL, '2022-06-14 16:00:54', -1, '2022-06-14 16:24:17', NULL, 1, 'clm0319@126.com', '');
