INSERT INTO `kb_basic` VALUES (1707281199984304129, NULL, '词云生成方法及设备', 1707241195564183553, 1707241015288803330, '2023-09-28 00:00:00', 1707280056801583105, 1707271818831998978, NULL, '[{\"path\":\"https://hcses-1251334741.cos.ap-nanjing.myqcloud.com/knowledgeonline/file/1695882391916.pdf\",\"name\":\"词云生成方法及设备.pdf\",\"url\":\"https://hcses-1251334741.cos.ap-nanjing.myqcloud.com/knowledgeonline/file/1695882391916.pdf\",\"md5\":\"e0588ae5a9ccc69570d052851540be00\"}]', NULL, 'ufwbirq', '本公开提供一种词云生成方法及设备，涉及计算机处理技术领域。该方法包括：通过词典中的词语对第一文本进行分词得到第一词语，词典中包括置信度大于或等于第一置信度阈值的第二词语，第二词语是从预设时间周期内生成的第二文本中预先提取得到的，置信度与第二词语在第二文本中的出现频次正相关，且与第二词语中的各个字分别在第二文本中的出现频次负相关；根据第一词语生成第一文本的词云。本公开可以将置信度较高的第二词语添加到', NULL, '[{\"weight\":35.33155,\"word\":\"词语\"},{\"weight\":24.48494,\"word\":\"第一\"},{\"weight\":20.594902,\"word\":\"所述\"},{\"weight\":14.605789,\"word\":\"文本\"},{\"weight\":11.344277,\"word\":\"可以\"},{\"weight\":10.042017,\"word\":\"置信\"},{\"weight\":7.92985,\"word\":\"包括\"},{\"weight\":7.4376364,\"word\":\"出现\"},{\"weight\":7.021255,\"word\":\"实施\"},{\"weight\":6.7291303,\"word\":\"公开\"},{\"weight\":5.6345825,\"word\":\"根据\"},{\"weight\":5.631128,\"word\":\"生成\"},{\"weight\":5.103994,\"word\":\"计算机\"},{\"weight\":4.790526,\"word\":\"des\"},{\"weight\":4.712353,\"word\":\"阈值\"},{\"weight\":4.709503,\"word\":\"确定\"},{\"weight\":4.426224,\"word\":\"预设\"},{\"weight\":4.175067,\"word\":\"词典\"},{\"weight\":4.1049814,\"word\":\"目标\"},{\"weight\":4.038425,\"word\":\"得到\"},{\"weight\":3.7580814,\"word\":\"设备\"},{\"weight\":3.700698,\"word\":\"执行\"},{\"weight\":3.6175303,\"word\":\"处理\"},{\"weight\":3.5362787,\"word\":\"装置\"},{\"weight\":3.409186,\"word\":\"用于\"},{\"weight\":3.4075446,\"word\":\"方法\"},{\"weight\":3.1553192,\"word\":\"进行\"},{\"weight\":3.1267142,\"word\":\"通过\"},{\"weight\":3.1040087,\"word\":\"构成\"},{\"weight\":3.0241933,\"word\":\"云生成\"},{\"weight\":2.9819589,\"word\":\"连接\"},{\"weight\":2.9264264,\"word\":\"信息\"},{\"weight\":2.8837934,\"word\":\"长度\"},{\"weight\":2.750894,\"word\":\"过程\"},{\"weight\":2.7485728,\"word\":\"分词\"},{\"weight\":2.7158666,\"word\":\"存储\"},{\"weight\":2.6265569,\"word\":\"方面\"},{\"weight\":2.603088,\"word\":\"程序\"},{\"weight\":2.6023827,\"word\":\"简称\"},{\"weight\":2.5977259,\"word\":\"大于\"},{\"weight\":2.5742545,\"word\":\"合并\"},{\"weight\":2.5721378,\"word\":\"关键\"},{\"weight\":2.5632615,\"word\":\"等于\"},{\"weight\":2.4740934,\"word\":\"技术\"},{\"weight\":2.458427,\"word\":\"多个\"},{\"weight\":2.4402452,\"word\":\"介质\"},{\"weight\":2.383481,\"word\":\"实现\"},{\"weight\":2.382894,\"word\":\"粒度\"},{\"weight\":2.3572927,\"word\":\"数量\"},{\"weight\":2.3345547,\"word\":\"重要性\"}]', 1, '2023-09-28 14:28:52', 1707241195564183553, 2, '2023-09-28 14:29:39', 1707241195564183553);
INSERT INTO `kb_basic` VALUES (1707283097286107138, NULL, '文档标签的生成方法装置终端和存储介质', 1707241195564183553, 1707241015288803330, '2023-09-28 00:00:00', 1707280056801583105, 1707271818831998978, NULL, '[{\"path\":\"upload/20230928/1695882776800.pdf\",\"name\":\"文档标签的生成方法装置终端和存储介质.pdf\",\"url\":\"https://hcses-1251334741.cos.ap-nanjing.myqcloud.com/knowledgeonline/file/1695882776800.pdf\",\"md5\":\"2cdd7df76c3c0a8dce575bdff3a5d4b1\"}]', NULL, 'ufwbirq', '本公开提供文档标签的生成方法及装置、终端和存储介质。文档标签的生成方法包括：基于第一文档的内容，为第一文档提供候选标签；响应于对候选标签的第一预设操作，生成与第一文档对应的标签；其中，标签与第二文档相关联，第二文档包括第一文档中的与标签对应的文档内容。在本公开的一些实施例中，标签与第二文档相关联，第二文档包括第一文档中的与标签对应的文档内容，如此，在与标签相关联的第二文档中进行了标签聚类，并且可以', NULL, '[{\"weight\":26.734974,\"word\":\"文档\"},{\"weight\":21.60647,\"word\":\"标签\"},{\"weight\":12.669923,\"word\":\"所述\"},{\"weight\":10.408874,\"word\":\"实施\"},{\"weight\":9.093846,\"word\":\"可以\"},{\"weight\":8.830203,\"word\":\"公开\"},{\"weight\":8.367299,\"word\":\"内容\"},{\"weight\":8.2218275,\"word\":\"包括\"},{\"weight\":8.00625,\"word\":\"第一\"},{\"weight\":5.087309,\"word\":\"装置\"},{\"weight\":4.974699,\"word\":\"生成\"},{\"weight\":4.728306,\"word\":\"候选\"},{\"weight\":4.545255,\"word\":\"提供\"},{\"weight\":4.4160514,\"word\":\"介质\"},{\"weight\":4.4043193,\"word\":\"计算机\"},{\"weight\":4.3508162,\"word\":\"存储\"},{\"weight\":4.2871046,\"word\":\"一些\"},{\"weight\":4.252391,\"word\":\"方法\"},{\"weight\":4.1953344,\"word\":\"执行\"},{\"weight\":4.167979,\"word\":\"程序\"},{\"weight\":3.42139,\"word\":\"用于\"},{\"weight\":3.3578396,\"word\":\"采用\"},{\"weight\":3.3441377,\"word\":\"对应\"},{\"weight\":3.0297613,\"word\":\"关联\"},{\"weight\":2.814396,\"word\":\"多个\"},{\"weight\":2.677764,\"word\":\"操作\"},{\"weight\":2.6109247,\"word\":\"存储器\"},{\"weight\":2.5832086,\"word\":\"可读\"},{\"weight\":2.4808722,\"word\":\"特征\"},{\"weight\":2.3877769,\"word\":\"设备\"},{\"weight\":2.346736,\"word\":\"实现\"},{\"weight\":2.313098,\"word\":\"des\"},{\"weight\":2.3050818,\"word\":\"代码\"},{\"weight\":2.290276,\"word\":\"预设\"},{\"weight\":2.2794857,\"word\