INSERT INTO `kb_basic` VALUES (1707284634775347201, NULL, '一种基于AI学习的智能防近视系统和方法', 1707241195564183553, 1707241015288803330, '2023-09-28 00:00:00', 1707280012912386049, 1707271818831998978, NULL, '[{\"url\":\"https://hcses-1251334741.cos.ap-nanjing.myqcloud.com/knowledgeonline/file/1695883176913.pdf\",\"path\":\"upload/20230928/1695883176913.pdf\",\"name\":\"一种基于AI学习的智能防近视系统和方法.pdf\",\"md5\":\"4b9f1655d6d3af906cfa3989ed05345e\"}]', NULL, 'ufwbirq', '一种基于AI学习的智能防近视系统，设有用眼行为监测单元，所述用眼行为监测单元包括距离传感器、加速度传感器；装置本体内还设有接收传感单元发回的用眼数据并进行处理的MCU中央处理器，服务器与MCU中央处理器交互传输数据，服务器学习大量用户发回的用眼数据不断优化算法，无线信号收发器和服务器的路径之间还设有移动终端，移动终端将服务器对用眼数据的分析结果显示给用户并在用户控制下分别与MCU中央处理器和服务器', NULL, '[{\"weight\":11.423909,\"word\":\"用户\"},{\"weight\":8.571974,\"word\":\"数据\"},{\"weight\":6.8602753,\"word\":\"服务器\"},{\"weight\":4.69256,\"word\":\"处理器\"},{\"weight\":4.6030645,\"word\":\"cu\"},{\"weight\":4.5303087,\"word\":\"中央\"},{\"weight\":4.240994,\"word\":\"距离\"},{\"weight\":4.0910926,\"word\":\"近视\"},{\"weight\":3.6011643,\"word\":\"传感器\"},{\"weight\":3.5143175,\"word\":\"所述\"},{\"weight\":3.45444,\"word\":\"发明\"},{\"weight\":3.3814545,\"word\":\"通过\"},{\"weight\":3.136602,\"word\":\"接收\"},{\"weight\":3.0690818,\"word\":\"改善\"},{\"weight\":2.8432074,\"word\":\"系统\"},{\"weight\":2.8058877,\"word\":\"收发\"},{\"weight\":2.7968006,\"word\":\"智能\"},{\"weight\":2.697847,\"word\":\"方式\"},{\"weight\":2.6469316,\"word\":\"实施\"},{\"weight\":2.625915,\"word\":\"设置\"},{\"weight\":2.5467887,\"word\":\"包括\"},{\"weight\":2.529326,\"word\":\"装置\"},{\"weight\":2.4527822,\"word\":\"习惯\"},{\"weight\":2.4480495,\"word\":\"监测\"},{\"weight\":2.4339633,\"word\":\"学习\"},{\"weight\":2.412695,\"word\":\"进行\"},{\"weight\":2.2940187,\"word\":\"信号\"},{\"weight\":2.2820778,\"word\":\"本体\"},{\"weight\":2.2498846,\"word\":\"方法\"},{\"weight\":2.191297,\"word\":\"报警\"},{\"weight\":2.1666017,\"word\":\"情况\"},{\"weight\":2.124905,\"word\":\"技术\"},{\"weight\":2.12017,\"word\":\"行为\"},{\"weight\":2.1171398,\"word\":\"la\"},{\"weight\":2.0654547,\