INSERT INTO `kb_basic` VALUES (1707285522684338177, NULL, '一种结构化数据版本管理方法与系统', 1707241195564183553, 1707241015288803330, '2023-09-28 00:00:00', 1707280171905867777, 1707271818831998978, NULL, '[{\"url\":\"https://hcses-1251334741.cos.ap-nanjing.myqcloud.com/knowledgeonline/file/1695883473695.pdf\",\"path\":\"upload/20230928/1695883473695.pdf\",\"name\":\"一种结构化数据版本管理方法与系统.pdf\",\"md5\":\"4646b3622500c30d43e0e8afa9999f2d\"}]', NULL, 'ufwbirq', '本发明公开了一种结构化数据版本管理方法，包括以下步骤：建立以ID为头结点的倒排索引；当需要写入数据时，先获取头部版本号head，然后将head+1生成新版本号重新赋予head，再将新版本的数据插入到倒排索引头部；当获取最新数据时，只需要定位到目标ID索引节点，再获取首节点的数据即可；当需要获取历史版本时，则指针向后继续移动，一种结构化数据版本管理系统，包括数据版本储存和索引模块，数据版本生成写入模', NULL, '[{\"weight\":21.615118,\"word\":\"数据\"},{\"weight\":6.586863,\"word\":\"发明\"},{\"weight\":5.1249256,\"word\":\"获取\"},{\"weight\":4.9051423,\"word\":\"索引\"},{\"weight\":4.499594,\"word\":\"实施\"},{\"weight\":4.3209743,\"word\":\"系统\"},{\"weight\":4.318112,\"word\":\"id\"},{\"weight\":3.7964182,\"word\":\"模块\"},{\"weight\":3.1639872,\"word\":\"管理\"},{\"weight\":3.0340295,\"word\":\"节点\"},{\"weight\":3.0068836,\"word\":\"最新\"},{\"weight\":2.834,\"word\":\"构化\"},{\"weight\":2.8010163,\"word\":\"方法\"},{\"weight\":2.6248322,\"word\":\"结构\"},{\"weight\":2.6234226,\"word\":\"用于\"},{\"weight\":2.532597,\"word\":\"256\"},{\"weight\":2.4970646,\"word\":\"sha\"},{\"weight\":2.279755,\"word\":\"所在\"},{\"weight\":2.246274,\"word\":\"目标\"},{\"weight\":2.2149887,\"word\":\"所述\"},{\"weight\":2.1580186,\"word\":\"插入\"},{\"weight\":2.1547346,\"word\":\"进行\"},{\"weight\":2.1356468,\"word\":\"技术\"},{\"weight\":2.0833402,\"word\":\"头部\"},{\"weight\":2.0241895,\"word\":\"方案\"},{\"weight\":1.977153,\"word\":\"描述\"},{\"weight\":1.9536307,\"word\":\"位置\"},{\"weight\":1.9488207,\"word\":\"存储\"},{\"weight\":1.9030032,\"word\":\"当前\"},{\"weight\":1.8683317,\"word\":\"写入\"},{\"weight\":1.8361845,\"word\":\"计算\"},{\"weight\":1.8333242,\"word\":\"01\"},{\"weight\":1.8040024,\"word\":\"根据\"},{\"weight\":1.7791945,\"word\":\"des\"},{\"weight\":1.7781048,\"w