INSERT INTO `kb_basic` VALUES (1707287099046387714, NULL, '表格数据的管理方法及装置', 1707241195564183553, 1707241015288803330, '2023-09-28 00:00:00', 1707280012912386049, 1707271818831998978, NULL, '[{\"url\":\"https://hcses-1251334741.cos.ap-nanjing.myqcloud.com/knowledgeonline/file/1695883848451.pdf\",\"path\":\"upload/20230928/1695883848451.pdf\",\"name\":\"表格数据的管理方法及装置.pdf\",\"md5\":\"c461cf51fcae58ffbaf9baa23b27f249\"}]', NULL, 'ufwbirq', '本申请公开了一种表格数据的管理方法。该方法包括：接收第一用户在第一终端新增的原始表格数据；根据第一用户在第一终端的第一管理操作，在所述原始表格数据中检索出待定义参数，并在第一终端输出；根据第一用户在第一终端的第二管理操作，在所述待定义参数中确定目标参数；创建基于所述目标参数为实体的多维表格。本申请解决了由于需要大量人为操作、推理、检索等确定目标实体造成的构建知识图谱各方面成本较高的技术问题。', NULL, '[{\"weight\":13.601445,\"word\":\"第一\"},{\"weight\":11.793163,\"word\":\"参数\"},{\"weight\":9.631416,\"word\":\"表格\"},{\"weight\":6.9467854,\"word\":\"终端\"},{\"weight\":6.717878,\"word\":\"目标\"},{\"weight\":6.661627,\"word\":\"管理\"},{\"weight\":6.6615834,\"word\":\"申请\"},{\"weight\":6.602819,\"word\":\"根据\"},{\"weight\":6.3276157,\"word\":\"数据\"},{\"weight\":6.2699647,\"word\":\"查询\"},{\"weight\":6.1633177,\"word\":\"实施\"},{\"weight\":5.32821,\"word\":\"所述\"},{\"weight\":5.026076,\"word\":\"关系\"},{\"weight\":4.910345,\"word\":\"关联\"},{\"weight\":4.824218,\"word\":\"问题\"},{\"weight\":4.7539096,\"word\":\"操作\"},{\"weight\":4.7256365,\"word\":\"可以\"},{\"weight\":4.6730337,\"word\":\"用户\"},{\"weight\":3.3868828,\"word\":\"成本\"},{\"weight\":3.2163405,\"word\":\"人员\"},{\"weight\":3.1236467,\"word\":\"界面\"},{\"weight\":3.0790849,\"word\":\"用于\"},{\"weight\":3.0770369,\"word\":\"原始\"},{\"weight\":3.0178895,\"word\":\"新增\"},{\"weight\":3.016737,\"word\":\"条件\"},{\"weight\":2.9505877,\"word\":\"确定\"},{\"weight\":2.8819256,\"word\":\"手机\"},{\"weight\":2.7302108,\"word\":\"步骤\"},{\"weight\":2.7009478,\"word\":\"待定\"},{\"weight\":2.6307158,\"word\":\"发明\"},{\"weight\":2.5803356,\"word\":\"检索\"},{\"weight\":2.489215,\"word\":\"输出\"},{\"weight\":2.452291,\"word\":\"des\"},{\"weight\":2.3900466,\"word\":\"接收\"},{\"weight\":2.3810377,\"word\":\"模块\"},